import React, { useState } from 'react';
import { 
  View, 
  Text, 
  StyleSheet, 
  ScrollView, 
  Alert 
} from 'react-native';
import { 
  Card, 
  Title, 
  Paragraph, 
  Button,
  Avatar,
  List,
  Switch,
  Chip,
  Divider,
  ActivityIndicator
} from 'react-native-paper';
import { MaterialCommunityIcons } from '@expo/vector-icons';
import { useLanguage } from '../contexts/LanguageContext';
import { theme, styles } from '../styles/theme';

const ProfileScreen = () => {
  const { t, changeLanguage, getAvailableLanguages, getCurrentLanguageDetails, isLoading } = useLanguage();
  
  const [userProfile, setUserProfile] = useState({
    name: 'राम सिंह',
    phone: '+91 98765 43210',
    location: 'गाजियाबाद, उत्तर प्रदेश',
    farmSize: '5 एकड़',
    crops: ['गेहूं', 'धान', 'मक्का'],
  });

  const [settings, setSettings] = useState({
    notifications: true,
    weatherAlerts: true,
    priceAlerts: true,
    diseaseAlerts: true,
    locationSharing: true,
  });

  const languages = [
    { code: 'hi', name: 'हिंदी', flag: '🇮🇳' },
    { code: 'en', name: 'English', flag: '🇺🇸' },
    { code: 'pa', name: 'ਪੰਜਾਬੀ', flag: '🇮🇳' },
    { code: 'gu', name: 'ગુજરાતી', flag: '🇮🇳' },
    { code: 'mr', name: 'मराठी', flag: '🇮🇳' },
    { code: 'bn', name: 'বাংলা', flag: '🇮🇳' },
    { code: 'te', name: 'తెలుగు', flag: '🇮🇳' },
    { code: 'ta', name: 'தமிழ்', flag: '🇮🇳' },
  ];

  const cropOptions = [
    'गेहूं', 'धान', 'मक्का', 'चना', 'मटर', 'सरसों', 'जौ', 'आलू',
    'प्याज', 'टमाटर', 'बैंगन', 'भिंडी', 'गोभी', 'गाजर', 'आम', 'अमरूद'
  ];

  const toggleSetting = (setting) => {
    setSettings(prev => ({
      ...prev,
      [setting]: !prev[setting]
    }));
  };

  const toggleCrop = (crop) => {
    setUserProfile(prev => ({
      ...prev,
      crops: prev.crops.includes(crop)
        ? prev.crops.filter(c => c !== crop)
        : [...prev.crops, crop]
    }));
  };

  const handleLogout = () => {
    Alert.alert(
      'लॉग आउट',
      'क्या आप वाकई लॉग आउट करना चाहते हैं?',
      [
        { text: 'रद्द करें', style: 'cancel' },
        { text: 'लॉग आउट', onPress: () => console.log('Logout') }
      ]
    );
  };

  const handleDeleteAccount = () => {
    Alert.alert(
      'खाता हटाएं',
      'यह एक स्थायी कार्रवाई है। क्या आप वाकई अपना खाता हटाना चाहते हैं?',
      [
        { text: 'रद्द करें', style: 'cancel' },
        { 
          text: 'हटाएं', 
          style: 'destructive',
          onPress: () => console.log('Delete account')
        }
      ]
    );
  };

  return (
    <ScrollView style={profileStyles.container}>
      {/* Profile Header */}
      <Card style={[styles.card, profileStyles.headerCard]}>
        <View style={profileStyles.profileHeader}>
          <Avatar.Text 
            size={80} 
            label={userProfile.name.charAt(0)} 
            style={profileStyles.avatar}
          />
          <View style={profileStyles.profileInfo}>
            <Title style={profileStyles.userName}>{userProfile.name}</Title>
            <Paragraph style={profileStyles.userPhone}>{userProfile.phone}</Paragraph>
            <View style={profileStyles.locationContainer}>
              <MaterialCommunityIcons 
                name="map-marker" 
                size={16} 
                color={theme.colors.primary} 
              />
              <Text style={profileStyles.userLocation}>{userProfile.location}</Text>
            </View>
            <View style={profileStyles.farmContainer}>
              <MaterialCommunityIcons 
                name="nature" 
                size={16} 
                color={theme.colors.primary} 
              />
              <Text style={profileStyles.farmSize}>खेत का आकार: {userProfile.farmSize}</Text>
            </View>
          </View>
        </View>
        <Button 
          mode="outlined" 
          style={profileStyles.editButton}
          onPress={() => Alert.alert('संपादन', 'प्रोफाइल संपादन सुविधा जल्द आ रही है!')}
        >
          प्रोफाइल संपादित करें
        </Button>
      </Card>

      {/* Language Selection */}
      <Card style={[styles.card]}>
        <Title style={profileStyles.sectionTitle}>भाषा चुनें</Title>
        <ScrollView horizontal showsHorizontalScrollIndicator={false}>
          <View style={profileStyles.languageContainer}>
            {languages.map((lang) => (
              <Chip
                key={lang.code}
                selected={userProfile.language === lang.name}
                onPress={() => setUserProfile(prev => ({
                  ...prev,
                  language: lang.name
                }))}
                style={[
                  profileStyles.languageChip,
                  userProfile.language === lang.name && profileStyles.selectedLanguage
                ]}
                avatar={<Text>{lang.flag}</Text>}
              >
                {lang.name}
              </Chip>
            ))}
          </View>
        </ScrollView>
      </Card>

      {/* Crop Selection */}
      <Card style={[styles.card]}>
        <Title style={profileStyles.sectionTitle}>आपकी फसलें</Title>
        <Paragraph style={profileStyles.sectionSubtitle}>
          आप जिन फसलों को उगाते हैं, उन्हें चुनें
        </Paragraph>
        <View style={profileStyles.cropContainer}>
          {cropOptions.map((crop) => (
            <Chip
              key={crop}
              selected={userProfile.crops.includes(crop)}
              onPress={() => toggleCrop(crop)}
              style={[
                profileStyles.cropChip,
                userProfile.crops.includes(crop) && profileStyles.selectedCrop
              ]}
            >
              {crop}
            </Chip>
          ))}
        </View>
      </Card>

      {/* Notification Settings */}
      <Card style={[styles.card]}>
        <Title style={profileStyles.sectionTitle}>सूचना सेटिंग्स</Title>
        
        <List.Item
          title="सभी सूचनाएं"
          description="ऐप की सभी सूचनाएं पाएं"
          left={props => <List.Icon {...props} icon="bell" />}
          right={() => (
            <Switch
              value={settings.notifications}
              onValueChange={() => toggleSetting('notifications')}
            />
          )}
        />
        
        <Divider />
        
        <List.Item
          title="मौसम चेतावनी"
          description="मौसम संबंधी अलर्ट पाएं"
          left={props => <List.Icon {...props} icon="weather-cloudy" />}
          right={() => (
            <Switch
              value={settings.weatherAlerts}
              onValueChange={() => toggleSetting('weatherAlerts')}
              disabled={!settings.notifications}
            />
          )}
        />
        
        <Divider />
        
        <List.Item
          title="मंडी भाव अलर्ट"
          description="कीमतों में बदलाव की जानकारी पाएं"
          left={props => <List.Icon {...props} icon="currency-inr" />}
          right={() => (
            <Switch
              value={settings.priceAlerts}
              onValueChange={() => toggleSetting('priceAlerts')}
              disabled={!settings.notifications}
            />
          )}
        />
        
        <Divider />
        
        <List.Item
          title="रोग चेतावनी"
          description="फसल की बीमारी संबंधी अलर्ट पाएं"
          left={props => <List.Icon {...props} icon="leaf" />}
          right={() => (
            <Switch
              value={settings.diseaseAlerts}
              onValueChange={() => toggleSetting('diseaseAlerts')}
              disabled={!settings.notifications}
            />
          )}
        />
      </Card>

      {/* Privacy Settings */}
      <Card style={[styles.card]}>
        <Title style={profileStyles.sectionTitle}>गोपनीयता सेटिंग्स</Title>
        
        <List.Item
          title="स्थान साझा करना"
          description="बेहतर सेवा के लिए अपना स्थान साझा करें"
          left={props => <List.Icon {...props} icon="map-marker" />}
          right={() => (
            <Switch
              value={settings.locationSharing}
              onValueChange={() => toggleSetting('locationSharing')}
            />
          )}
        />
      </Card>

      {/* App Information */}
      <Card style={[styles.card]}>
        <Title style={profileStyles.sectionTitle}>ऐप की जानकारी</Title>
        
        <List.Item
          title="संस्करण"
          description="1.0.0"
          left={props => <List.Icon {...props} icon="information" />}
        />
        
        <Divider />
        
        <List.Item
          title="सहायता और फीडबैक"
          description="हमसे संपर्क करें"
          left={props => <List.Icon {...props} icon="help-circle" />}
          right={props => <List.Icon {...props} icon="chevron-right" />}
          onPress={() => Alert.alert('सहायता', 'सहायता केंद्र जल्द खुलेगा!')}
        />
        
        <Divider />
        
        <List.Item
          title="नियम और शर्तें"
          description="उपयोग की शर्तें पढ़ें"
          left={props => <List.Icon {...props} icon="file-document" />}
          right={props => <List.Icon {...props} icon="chevron-right" />}
          onPress={() => Alert.alert('नियम', 'नियम और शर्तें जल्द उपलब्ध होंगी!')}
        />
        
        <Divider />
        
        <List.Item
          title="गोपनीयता नीति"
          description="डेटा उपयोग नीति देखें"
          left={props => <List.Icon {...props} icon="shield-check" />}
          right={props => <List.Icon {...props} icon="chevron-right" />}
          onPress={() => Alert.alert('गोपनीयता', 'गोपनीयता नीति जल्द उपलब्ध होगी!')}
        />
      </Card>

      {/* Account Actions */}
      <Card style={[styles.card]}>
        <Title style={profileStyles.sectionTitle}>खाता प्रबंधन</Title>
        
        <Button
          mode="outlined"
          style={[profileStyles.actionButton, { borderColor: theme.colors.primary }]}
          onPress={handleLogout}
        >
          <MaterialCommunityIcons name="logout" size={20} />
          {'  '}लॉग आउट
        </Button>
        
        <Button
          mode="outlined"
          style={[profileStyles.actionButton, { borderColor: theme.colors.error }]}
          textColor={theme.colors.error}
          onPress={handleDeleteAccount}
        >
          <MaterialCommunityIcons name="delete" size={20} />
          {'  '}खाता हटाएं
        </Button>
      </Card>

      {/* Footer */}
      <Card style={[styles.card, { marginBottom: 20 }]}>
        <View style={profileStyles.footer}>
          <Text style={profileStyles.footerText}>
            कृषि सहायक - किसानों का डिजिटल साथी
          </Text>
          <Text style={profileStyles.footerSubtext}>
            Made with ❤️ for Indian Farmers
          </Text>
        </View>
      </Card>
    </ScrollView>
  );
};

const profileStyles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: theme.colors.background,
  },
  headerCard: {
    backgroundColor: theme.colors.surface,
  },
  profileHeader: {
    flexDirection: 'row',
    alignItems: 'center',
    marginBottom: 20,
  },
  avatar: {
    backgroundColor: theme.colors.primary,
  },
  profileInfo: {
    marginLeft: 20,
    flex: 1,
  },
  userName: {
    fontSize: 22,
    fontWeight: 'bold',
    color: theme.colors.text,
  },
  userPhone: {
    fontSize: 14,
    color: theme.colors.text,
    opacity: 0.7,
  },
  locationContainer: {
    flexDirection: 'row',
    alignItems: 'center',
    marginTop: 5,
  },
  userLocation: {
    fontSize: 14,
    color: theme.colors.text,
    marginLeft: 5,
  },
  farmContainer: {
    flexDirection: 'row',
    alignItems: 'center',
    marginTop: 5,
  },
  farmSize: {
    fontSize: 14,
    color: theme.colors.text,
    marginLeft: 5,
  },
  editButton: {
    borderColor: theme.colors.primary,
  },
  sectionTitle: {
    fontSize: 18,
    fontWeight: 'bold',
    color: theme.colors.primary,
    marginBottom: 10,
  },
  sectionSubtitle: {
    fontSize: 14,
    color: theme.colors.text,
    opacity: 0.7,
    marginBottom: 15,
  },
  languageContainer: {
    flexDirection: 'row',
    gap: 10,
  },
  languageChip: {
    backgroundColor: '#E8F5E8',
    marginRight: 5,
  },
  selectedLanguage: {
    backgroundColor: theme.colors.primary,
  },
  cropContainer: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 8,
  },
  cropChip: {
    backgroundColor: '#E8F5E8',
    marginVertical: 2,
  },
  selectedCrop: {
    backgroundColor: theme.colors.secondary,
  },
  actionButton: {
    marginVertical: 8,
    paddingVertical: 8,
  },
  footer: {
    alignItems: 'center',
    paddingVertical: 10,
  },
  footerText: {
    fontSize: 16,
    fontWeight: 'bold',
    color: theme.colors.primary,
    textAlign: 'center',
  },
  footerSubtext: {
    fontSize: 12,
    color: theme.colors.text,
    opacity: 0.7,
    textAlign: 'center',
    marginTop: 5,
  },
});

export default ProfileScreen;
